// --- Shared-calling-code disambiguation (hand-maintained) -------------------
// Several calling codes are shared by more than one country (e.g. +1 is US,
// Canada and the NANP dependencies; +44 is the UK and its crown dependencies).
// The data below pins the right country for a given national number, falling
// back to a per-code default (the biggest country) when no specific match is
// found. Edited in scripts/gen-phone-data.ts — regenerate to apply changes.

/**
 * For calling codes shared by several countries, the "biggest" country to
 * default to when a number can't be pinned to a specific country (e.g. by area
 * code). Keyed by the calling code exactly as stored on CountryPhoneConfig
 * ("+1"). Without this, the first catalogue entry (alphabetical by ISO code)
 * would win — so a bare "+1" would resolve to Antigua (AG) instead of the US.
 */
export const CALLING_CODE_DEFAULTS: ReadonlyMap<string, CountryCode> = new Map<string, CountryCode>([
  ["+1", "US"],
  ["+7", "RU"],
  ["+39", "IT"],
  ["+44", "GB"],
  ["+47", "NO"],
  ["+61", "AU"],
  ["+64", "NZ"],
  ["+212", "MA"],
  ["+262", "RE"],
  ["+358", "FI"],
  ["+500", "FK"],
  ["+590", "GP"],
  ["+599", "CW"],
  ["+672", "NF"],
]);

