/**
 * Per-calling-code national-number prefix -> ISO maps, used to tell apart
 * countries that share a calling code by their leading digits (area code). The
 * longest matching prefix wins; if no prefix matches, the CALLING_CODE_DEFAULTS
 * entry for the code is used. Prefixes are only listed where they unambiguously
 * belong to a non-default country (e.g. +44 1481 -> Guernsey; +7 6/7 ->
 * Kazakhstan). Codes whose members share identical number ranges (+590
 * Guadeloupe / St. Martin / St. Barthélemy) are left to the default.
 */
export const CALLING_CODE_AREA_PREFIXES: ReadonlyMap<string, ReadonlyMap<string, CountryCode>> = new Map([
  ["+1", NANP_AREA_CODE_TO_COUNTRY],
  ["+39", new Map([["06698", "VA"]])], // Vatican City (Rome 06 698 block)
  [
    "+44",
    new Map([
      ["1481", "GG"],
      ["1534", "JE"],
      ["1624", "IM"],
    ]),
  ], // Guernsey / Jersey / Isle of Man
  ["+47", new Map([["79", "SJ"]])], // Svalbard & Jan Mayen
  ["+212", new Map([["528", "EH"]])], // Western Sahara (Laâyoune)
  ["+262", new Map([["639", "YT"]])], // Mayotte
  ["+358", new Map([["18", "AX"]])], // Åland Islands
  [
    "+599",
    new Map([
      ["31", "BQ"],
      ["41", "BQ"],
      ["7", "BQ"],
    ]),
  ], // Bonaire / Saba / Sint Eustatius (Curaçao is the +599 default)
  ["+672", new Map([["1", "AQ"]])], // Australian Antarctic (Norfolk Island is the +672 default)
  [
    "+7",
    new Map([
      ["6", "KZ"],
      ["7", "KZ"],
    ]),
  ], // Kazakhstan (Russia is the +7 default)
]);
